63 PreservedAnalyses InstCountPass::run(Function &F,
64                                      FunctionAnalysisManager &FAM) {
65   LLVM_DEBUG(dbgs() << "INSTCOUNT: running on function " << F.getName()
66                     << "\n");
67   InstCount().visit(F);
68 
69   return PreservedAnalyses::all();
